import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import JobDetailsBox from "../common/jobdetail";
import AddJobModal from "../forms/employer/job";
import { GetFilter } from "../../api/api";
import FilterJson from "../json/filterjson";
import JobTable from "../common/jobTable";
import EmployeeHeader from "../common/header";
import EmployeeFooter from "../common/footer";
import SelectBox from "../common/Common function/SelectBox";
import CustomButton from "../common/button";
import LmiafieldsPermission from "../forms/admin/LmiafieldsPermission";
import { FaEyeSlash } from "react-icons/fa";
function LimaContainer(props) {
  /*show Modal and props state */
  let [apiCall, setApiCall] = useState(false);
  let [showAddJobsModal, setShowAddJobsModal] = useState(false);
  let [showJobDetails, setShowJobDetails] = useState(false);
  const [JobId, setJobId] = useState([]);
  const [pageNo, setPageNo] = useState(localStorage.getItem("PageNo") || 1);
  /*Filter and search state */
  const [categoryFilterValue, setCategoryFilterValue] = useState("");
  const [openPermission, setOpenPermission] = useState(false);
  const [SkillFilterValue, setSkillFilterValue] = useState(
    props ? props.skill : ""
  );
  const [locationFilterValue, setLocationFilterValue] = useState("");
  const [jobSwapFilterValue, setJobSwapFilterValue] = useState("");
  const [search, setSearch] = useState("");
  const [searcherror, setSearchError] = useState("");
  const [company, setCompany] = useState("");
  let [Json, setJson] = useState([]);
  let userType = localStorage.getItem("userType");

  /*Function to get the jSon */
  const JsonData = async () => {
    try {
      let Json = await GetFilter();
      if (Json.data.message === "No data found") {
        setJson([]);
      } else {
        setJson(Json.data.data);
      }
      setJson(Json.data.data);
    } catch (err) {
      console.log(err);
    }
  };

  /*Render function to get the job */
  useEffect(() => {
    JsonData();
    if ((search === "") === true) {
      setSearchError("");
    }
  }, [
    categoryFilterValue,
    SkillFilterValue,
    locationFilterValue,
    jobSwapFilterValue,
    apiCall,
    search,
    company,
  ]);

  /* Function to show the Job detail data */
  const JobDetail = (e) => {
    setShowJobDetails(true);
    setJobId(e);
  };

  /* Function to show the single data to update job */
  const editJob = (e) => {
    // e.preventDefault();
    setShowAddJobsModal(true);
    setJobId(e);
  };
  /*Function to search the Job */
  const onSearch = (e) => {
    const inputValue = e.target.value;
    setSearch(inputValue);
    setPageNo(1);
    if (inputValue.length > 0) {
      if (/[-]?\d+(\.\d+)?/.test(inputValue.charAt(0))) {
        setSearchError("Job cannot start with a number.");
      } else if (!/^[A-Za-z0-9 ]*$/.test(inputValue)) {
        setSearchError("Cannot use special characters.");
      } else {
        setSearchError("");
      }
    } else {
      setSearchError("");
    }
  };
  /*Skill Json for not having same data */
  const Skill =
    Json && Json.Skill
      ? Json.Skill.filter(
        (thing, index, self) =>
          index === self.findIndex((t) => t.value === thing.value)
      )
      : [];
  return (
    <>
      <div
        className={
          userType === "company"
            ? "bg-default-1 pt-9 pb-10 pb-xl-30 pb-13 position-relative overflow-hidden"
            : "site-wrapper overflow-hidden bg-default-2"
        }
      >
        {userType === "company" ? (
          <EmployeeHeader />
        ) : (
          <>
            {/* <!-- Header Area --> */}
            {/* <AdminHeader heading={"LMIA status"} /> */}
            {/* <!-- navbar- --> */}
            {/* <AdminSidebar heading={"LMIA status"} /> */}
          </>
        )}

        <div
          className={
            showJobDetails === false
              ? userType === "company"
                ? "mt-16"
                : "dashboard-main-container mt-14"
              : "d-none"
          }
          id="dashboard-body"
        >
          <div className={`container${userType === "admin" ? "-fluid" : ""}`}>
            <div className="mb-18">
              <div className="mb-4 align-items-center">
                <div className={userType === "company" ? "" : "page___heading"}>
                  <h3
                    className="font-size-6 mb-0 "
                    style={{
                      marginTop: userType === "company" ? "110px" : null,
                    }}
                  >
                    LMIA of Jobs{" "}
                  </h3>
                </div>
                {/*<-- Job Search and Filter -->*/}
                {userType === "company" ? null : (
                  <div className="row m-0 align-items-center">
                    <div className="col p-1 form_group mb-3">
                      <p className="input_label">Search:</p>
                      <input
                        required
                        type="text"
                        className="form-control input-height w-100"
                        placeholder={"Search Job"}
                        value={search}
                        name={"name"}
                        onChange={(e) => onSearch(e)}
                      />
                      <small className="text-danger">{searcherror}</small>
                    </div>
                    <div className="col p-1 form_group mb-3">
                      <p className="input_label">Client Name:</p>
                      <input
                        required
                        type="text"
                        className="form-control input-height w-100"
                        placeholder={"Client name"}
                        value={company}
                        name={"company_name"}
                        onChange={(e) => {
                          setCompany(e.target.value);
                          setPageNo(1);
                        }}
                      />
                    </div>
                    <div className="col p-1 form_group mb-3">
                      <p className="input_label">Filter by Job Category:</p>
                      <div className="select_div">
                        <SelectBox
                          Width={"yes"} options={Json && Json?.Category ? Json?.Category.map((option) => ({
                            value: option.id,
                            label: option.value,
                          })) : []}
                          selectedValue={categoryFilterValue}
                          onChange={(e) => {
                            setCategoryFilterValue(e ? e.value : null);
                            setPageNo(1);
                          }}
                          type={"category"}
                        />
                      </div>
                    </div>
                    <div className="col p-1 form_group mb-3">
                      <p className="input_label">Filter by Job Type:</p>
                      <div className="select_div">
                        <SelectBox
                          Width={"yes"} options={(FilterJson.job_type.map((option) => ({
                            value: option,
                            label: option,
                          })) || [])}
                          selectedValue={jobSwapFilterValue}
                          onChange={(e) => {
                            console.log(e)
                            setJobSwapFilterValue(e ? e.value : null);
                            setPageNo(1);
                          }}
                          type={"job_type"}
                        />

                      </div>
                    </div>
                    <div className="col p-1 form_group mb-3">
                      <p className="input_label">Filter by Job Skill:</p>
                      <div className="select_div">
                        <SelectBox
                          Width={"yes"} options={(Skill.map((option) => ({
                            value: option.value,
                            label: option.value,
                          })) || [])}
                          selectedValue={SkillFilterValue}
                          onChange={(e) => {
                            setSkillFilterValue(e ? e.value : null);
                            setPageNo(1);
                          }}
                          type={"skill"}
                        />
                      </div>
                    </div>
                    <div className="col p-1 form_group mb-3">
                      <p className="input_label">Filter by Job Location:</p>
                      <div className="select_div">
                        <SelectBox
                          Width={"yes"} options={(FilterJson.location.map((option) => ({
                            value: option.country,
                            label: option.country,
                          })) || [])}
                          selectedValue={locationFilterValue}
                          onChange={(e) => {
                            setLocationFilterValue(e ? e.value : null);
                            setPageNo(1);
                          }}
                          type={"location"}
                        />
                      </div>
                    </div>
                    <div className={props.employee_id ? "d-none" : "text-end col-xl-12"}>
                      <div className="float-md-right d-flex">
                        <CustomButton
                          className="font-size-3 rounded-3 btn btn-primary border-0"
                          onClick={() => editJob("0")}
                          title="Add LMIA"
                        >
                          Add LMIA
                        </CustomButton>
                        {/* <div className="mt-4">
                        <CommonThreeDots tableName={"job"} tableData={allJob} />
                      </div> */}
                        {/*<-- Add Lmia fields permission  Modal -->*/}
                        <button className=" btn-sm btn-primary border-0 mx-2"
                          onClick={() => setOpenPermission("0")}
                          title="Hide Columns "
                        >
                          <FaEyeSlash /></button>
                      </div>
                      <small className="text-danger">{searcherror}</small>
                    </div>
                  </div>
                )}
              </div>
              {/*<-- Job List Table -->*/}
              <JobTable
                search={search}
                jobSwapFilterValue={jobSwapFilterValue}
                locationFilterValue={locationFilterValue}
                SkillFilterValue={SkillFilterValue}
                categoryFilterValue={categoryFilterValue}
                company={company}
                JobDetail={JobDetail}
                apiCall={apiCall}
                setApiCall={setApiCall}
                // skill={props.skill}
                // employee_id={props.employee_id}
                selfJob={"no"}
                response="lmia"
                pageNo={pageNo}
                setpageNo={setPageNo}
                company_id={props?.company_id}
                page="lmia"
              />
            </div>
          </div>
        </div>
        {/*<-- Job Detail -->*/}
        {showJobDetails === true ? (
          <div
            className={
              userType === "company"
                ? "mt-16"
                : "dashboard-main-container mt-14"
            }
          >
            <div className="container-fluid">
              <div className="row justify-content-center">
                <div className="col-12 dark-mode-texts">
                  <div className="mb-9">
                    <Link
                      to={""}
                      onClick={() => setShowJobDetails(false)}
                      className="d-flex align-items-center ml-4"
                    >
                      <i className="icon icon-small-left bg-white circle-40 mr-5 font-size-7 text-black font-weight-bold shadow-8"></i>
                      <span className="text-uppercase font-size-3 font-weight-bold text-gray">
                        Back
                      </span>
                    </Link>
                  </div>
                </div>
              </div>
              <div className="mb-18">
                <JobDetailsBox jobdata={JobId} />
              </div>
            </div>
          </div>
        ) : null}
      </div>
      {showAddJobsModal ? (
        <AddJobModal
          show={showAddJobsModal}
          jobdata={props.company_id ? "" : JobId}
          admin={"admin"}
          apiCall={apiCall}
          setApiCall={setApiCall}
          close={() => setShowAddJobsModal(false)}
          company_id={props.company_id || ""}
        />
      ) : null}
      {openPermission ?
        <LmiafieldsPermission
          show={openPermission}
          apiCall={apiCall}
          setApiCall={setApiCall}
          close={() => setOpenPermission(false)}
          page="lmia"
        />
        : null}
      {userType === "company" ? <EmployeeFooter /> : null}
    </>
  );
}

export default LimaContainer;
